import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import api from '../utils/api';
import { FiAward, FiMessageSquare, FiHeart } from 'react-icons/fi';

const Profile = () => {
  const { id } = useParams();
  const [profile, setProfile] = useState(null);
  const [questions, setQuestions] = useState([]);
  const [answers, setAnswers] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchProfile();
  }, [id]);

  const fetchProfile = async () => {
    try {
      const [profileRes, questionsRes, answersRes] = await Promise.all([
        api.get(`/users/${id}`),
        api.get(`/users/${id}/questions`),
        api.get(`/users/${id}/answers`)
      ]);
      setProfile(profileRes.data);
      setQuestions(questionsRes.data.questions);
      setAnswers(answersRes.data.answers);
    } catch (error) {
      console.error('Error fetching profile:', error);
    }
    setLoading(false);
  };

  if (loading) return <div className="text-center py-8">Loading...</div>;
  if (!profile) return <div className="text-center py-8">User not found</div>;

  return (
    <div className="max-w-4xl mx-auto">
      <div className="bg-white rounded-lg shadow-md p-6 mb-6">
        <div className="flex items-center">
          <div className="w-20 h-20 bg-orange-400 rounded-full flex items-center justify-center text-white text-3xl font-bold mr-6">
            {profile.name?.charAt(0).toUpperCase()}
          </div>
          <div>
            <h1 className="text-3xl font-bold">{profile.name}</h1>
            <p className="text-gray-500">{profile.email}</p>
            <div className="flex items-center gap-4 mt-2">
              <span className="bg-orange-100 text-orange-800 px-3 py-1 rounded-full text-sm">
                {profile.reputation} reputation
              </span>
              {profile.role !== 'user' && (
                <span className="bg-yellow-100 text-yellow-800 px-3 py-1 rounded-full text-sm">
                  {profile.role?.charAt(0).toUpperCase() + profile.role?.slice(1)}
                </span>
              )}
            </div>
          </div>
        </div>

        {profile.badges?.length > 0 && (
          <div className="mt-6 pt-6 border-t">
            <h3 className="font-semibold mb-3 flex items-center">
              <FiAward className="mr-2" /> Badges
            </h3>
            <div className="flex flex-wrap gap-2">
              {profile.badges.map((badge, i) => (
                <span key={i} className={`px-3 py-1 rounded-full text-sm ${
                  badge.type === 'gold' ? 'bg-yellow-100 text-yellow-800' :
                  badge.type === 'silver' ? 'bg-gray-100 text-gray-800' :
                  'bg-orange-100 text-orange-800'
                }`}>
                  {badge.name}
                </span>
              ))}
            </div>
          </div>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-bold mb-4 flex items-center">
            <FiMessageSquare className="mr-2" /> Questions ({questions.length})
          </h2>
          <div className="space-y-3">
            {questions.slice(0, 5).map(q => (
              <Link key={q._id} to={`/questions/${q._id}`} className="block hover:text-orange-600">
                {q.title}
              </Link>
            ))}
          </div>
        </div>

        <div className="bg-white rounded-lg shadow-md p-6">
          <h2 className="text-xl font-bold mb-4 flex items-center">
            <FiHeart className="mr-2" /> Answers ({answers.length})
          </h2>
          <div className="space-y-3">
            {answers.slice(0, 5).map(a => (
              <div key={a._id} className="text-sm">
                <Link to={`/questions/${a.question?._id}`} className="hover:text-orange-600">
                  {a.question?.title}
                </Link>
                <p className="text-gray-500 mt-1">{a.body?.substring(0, 100)}...</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Profile;
